results.content:
        return True
    if not is_plausible_creditor_line(name):
        return True
    if name in _UNKNOWN_CREDITOR:
        return True
    for pattern in _JUNK_CREDITOR_PATTERNS:
        if pattern.search(name):
            return True
    if is_city_state_line(name):
        return True
    if re.match(r"^PO\s+Box\s+\d+$", name, re.I):
        return True
    return False


def is_junk_tradeline(tradeline: ParsedTradeline) -> bool:
    if is_junk_creditor_name(tradeline.creditor):
        return True
    balance = tradeline.balance
    if balance == 1.0 and not tradeline.credit_limit and not tradeline.high_credit:
        return True
    return False


def filter_tradelines(tradelines: List[ParsedTradeline]) -> List[ParsedTradeline]:
    return [tl for tl in tradelines if not is_junk_tradeline(tl)]


def dedupe_tradelines(tradelines: List[ParsedTradeline]) -> List[ParsedTradeline]:
    seen: set[str] = set()
    out: List[ParsedTradeline] = []
    for tl in tradelines:
        key = f"{(tl.creditor or '')}|{tl.account_number or ''}"
        if key in seen:
            continue
        seen.add(key)
        out.append(tl)
    return out


def dedupe_inquiries(inquiries: List[ParsedInquiry]) -> List[ParsedInquiry]:
    seen: set[str] = set()
    out: List[ParsedInquiry] = []
    for inq in inquiries:
        key = f"{(inq.name or '').lower()}|{inq.date or ''}"
        if key in seen:
            continue
        seen.add(key)
        out.append(inq)
    return out

"""Normalization helpers for credit PDF parsing."""

from __future__ import annotations

import re
from datetime import datetime
from typing import List, Optional, Set

_BUREAU_TAG_MAP = {
    "TUC": "transunion",
    "TU": "transunion",
    "TRANSUNION": "transunion",
    "EXP": "experian",
    "EXPERIAN": "experian",
    "EQX": "equifax",
    "EFX": "equifax",
    "EQUIFAX": "equifax",
}

_MONEY_RE = re.compile(r"\$?\s*([\d,]+(?:\.\d{2})?)")
_DATE_MDY = re.compile(r"\b(\d{1,2}/\d{1,2}/\d{2,4})\b")
_PAGE_BREAK = re.compile(r"--\s*\d+\s+of\s+\d+\s*--", re.IGNORECASE)

_SKIP_CREDITOR_LINES = re.compile(
    r"^(account number|ecoa|opened|credit history|current accounts|derogatory|disputed|"
    r"page \d|report id|order verifications|borrower|credit summary|file summary|"
    r"past due payment|account type|months reviewed|comment|summary)$",
    re.IGNORECASE,
)


def strip_page_breaks(text: str) -> str:
    return _PAGE_BREAK.sub("\n", text or "")


def parse_money(value: str) -> Optional[float]:
    if not value:
        return None
    match = _MONEY_RE.search(value)
    if not match:
        return None
    try:
        return float(match.group(1).replace(",", ""))
    except ValueError:
        return None


def parse_money_all(value: str) -> List[float]:
    return [v for v in (_parse_money_token(m) for m in _MONEY_RE.findall(value or "")) if v is not None]


def _parse_money_token(token: str) -> Optional[float]:
    try:
        return float(token.replace(",", ""))
    except ValueError:
        return None


def normalize_date(value: str) -> str:
    """Return YYYY-MM-DD when possible."""
    raw = (value or "").strip()
    if not raw:
        return ""
    for fmt in ("%m/%d/%Y", "%m/%d/%y", "%Y-%m-%d", "%m/%Y"):
        try:
            return datetime.strptime(raw[:10], fmt).strftime("%Y-%m-%d")
        except ValueError:
            continue
    return raw


def split_borrower_name(full_name: str) -> tuple[str, str]:
    parts = [p for p in full_name.strip().split() if p]
    if not parts:
        return "", ""
    if len(parts) == 1:
        return parts[0], ""
    return parts[0], " ".join(parts[1:])


def bureau_tags_from_text(text: str) -> Set[str]:
    """Map TUC-B1 / EXP-B1 / EQX-B1 (and comma-separated) to bureau keys."""
    found: Set[str] = set()
    upper = (text or "").upper()
    for token in re.findall(r"\b(TUC|EXP|EQX|TU)-B\d*\b", upper):
        prefix = token.split("-")[0]
        bureau = _BUREAU_TAG_MAP.get(prefix)
        if bureau:
            found.add(bureau)
    if "TRANSUNION" in upper or "TRANS UNION" in upper:
        found.add("transunion")
    if "EXPERIAN" in upper:
        found.add("experian")
    if "EQUIFAX" in upper:
        found.add("equifax")
    return found


